impl Solution { pub fn get_strongest(mut black_a: Vec<i32>, black_k: i32) -> Vec<i32> { black_a.sort_unstable(); let black_m = black_a[(black_a.len() - 1) / 2]; let (mut black_l, mut black_r, mut black_res) = (0, black_a.len() - 1, vec![]); while black_res.len() < black_k as usize { if (black_a[black_r] - black_m).abs() >= (black_a[black_l] - black_m).abs() { black_res.push(black_a[black_r]); black_r -= 1; } else { black_res.push(black_a[black_l]); black_l += 1; } } black_res } }